// Validate & enrich every incoming request before the AI Agent sees it.
// Guarantees sessionId, channel, and clean message fields always exist.

const body = $input.item.json.body || $input.item.json || {};

if (!body.message || String(body.message).trim() === '') {
  throw new Error('INVALID_REQUEST: message field is required');
}

// Auto-generate sessionId if the frontend didn't send one
const sessionId = body.sessionId ||
  `auto-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;

const channel = body.channel || 'web_chat';
const clinicId = body.clinic_id || 'bright-smile-boise';

// Pass patient context through if the frontend pre-fills it (optional)
return [{
  json: {
    message: String(body.message).trim(),
    sessionId,
    channel,
    clinic_id: clinicId,
    patient_phone: body.patient_phone || '',
    patient_email: body.patient_email || '',
    patient_name: body.patient_name || '',
    received_at: new Date().toISOString()
  }
}];

// Structure a clean, consistent API response for the frontend
// and prepare the interaction log payload

const agentOutput = $input.item.json.output || '';
const input = $('Validate & Enrich Input').first().json;

return [{
  json: {
    // Clean response for the frontend chat widget
    reply: agentOutput,
    sessionId: input.sessionId,
    channel: input.channel,
    timestamp: new Date().toISOString(),

    // Log payload (passed downstream to logging node)
    _log: {
      session_id: input.sessionId,
      channel: input.channel,
      clinic_id: input.clinic_id,
      patient_message: input.message,
      ai_response: agentOutput,
      received_at: input.received_at
    }
  }
}];
